import{_ as e,o,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Online Safety","description":"","frontmatter":{},"headers":[],"relativePath":"theory/social/online-safety.md","filePath":"theory/social/online-safety.md"}'),a={name:"theory/social/online-safety.md"};function n(s,t,d,l,h,c){return o(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="online-safety" tabindex="-1">Online Safety <a class="header-anchor" href="#online-safety" aria-label="Permalink to &quot;Online Safety&quot;">​</a></h1><p>Every time you connect to the internet, you enter a space with both opportunity and risk. Understanding how online threats work — and what you can do to protect yourself — is not optional in the modern world.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10–11</p><p>Online safety (email threats, safe internet use, digital footprint) is introduced at Grade 10. Grade 11 extends with more detailed threat types and protection measures.</p></div><hr><h2 id="the-online-threat-landscape" tabindex="-1">The Online Threat Landscape <a class="header-anchor" href="#the-online-threat-landscape" aria-label="Permalink to &quot;The Online Threat Landscape&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Threats</th></tr></thead><tbody><tr><td><strong>Privacy threats</strong></td><td>Data collection, surveillance, digital footprint</td></tr><tr><td><strong>Social engineering</strong></td><td>Phishing, smishing, vishing, pretexting</td></tr><tr><td><strong>Technical threats</strong></td><td>Malware, ransomware, hacking, DDoS</td></tr><tr><td><strong>Identity threats</strong></td><td>Identity theft, account takeover</td></tr><tr><td><strong>Content threats</strong></td><td>Cyberbullying, misinformation, inappropriate content</td></tr><tr><td><strong>Financial threats</strong></td><td>Scams, fake e-commerce, card fraud</td></tr></tbody></table><hr><h2 id="phishing-and-social-engineering" tabindex="-1">Phishing and Social Engineering <a class="header-anchor" href="#phishing-and-social-engineering" aria-label="Permalink to &quot;Phishing and Social Engineering&quot;">​</a></h2><p><strong>Social engineering</strong> manipulates people into revealing information or taking actions that compromise security — exploiting human psychology rather than technical vulnerabilities.</p><h3 id="types-of-phishing" tabindex="-1">Types of Phishing <a class="header-anchor" href="#types-of-phishing" aria-label="Permalink to &quot;Types of Phishing&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Channel</th><th>Target</th></tr></thead><tbody><tr><td><strong>Phishing</strong></td><td>Mass email</td><td>Anyone</td></tr><tr><td><strong>Spear phishing</strong></td><td>Targeted email</td><td>Specific person/organisation</td></tr><tr><td><strong>Whaling</strong></td><td>Targeted email</td><td>Senior executives (CEO, CFO)</td></tr><tr><td><strong>Smishing</strong></td><td>SMS</td><td>Mobile users</td></tr><tr><td><strong>Vishing</strong></td><td>Phone call</td><td>Anyone</td></tr><tr><td><strong>Pharming</strong></td><td>Redirect website</td><td>Anyone visiting a compromised site</td></tr></tbody></table><h3 id="how-to-identify-phishing-emails" tabindex="-1">How to Identify Phishing Emails <a class="header-anchor" href="#how-to-identify-phishing-emails" aria-label="Permalink to &quot;How to Identify Phishing Emails&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Red flag</th><th>Example</th></tr></thead><tbody><tr><td>Urgent language</td><td>&quot;Your account will be suspended in 24 hours!&quot;</td></tr><tr><td>Generic greeting</td><td>&quot;Dear Customer&quot; instead of your name</td></tr><tr><td>Sender mismatch</td><td>Display name says &quot;FNB Bank&quot; but email is <code>fnb-help@gmail.com</code></td></tr><tr><td>Suspicious link</td><td>Hover shows <code>http://fnb-scam.ru/login</code></td></tr><tr><td>Grammar errors</td><td>Poor spelling, awkward phrasing</td></tr><tr><td>Requests credentials</td><td>&quot;Reply with your password to confirm&quot;</td></tr><tr><td>Unexpected attachments</td><td>Unsolicited invoice or report</td></tr></tbody></table><hr><h2 id="safe-internet-practices" tabindex="-1">Safe Internet Practices <a class="header-anchor" href="#safe-internet-practices" aria-label="Permalink to &quot;Safe Internet Practices&quot;">​</a></h2><h3 id="passwords" tabindex="-1">Passwords <a class="header-anchor" href="#passwords" aria-label="Permalink to &quot;Passwords&quot;">​</a></h3><ul><li>Use <strong>long, unique passwords</strong> for every account (16+ characters)</li><li>Use a <strong>password manager</strong> to generate and store passwords</li><li>Never reuse passwords across sites</li><li>Enable <strong>two-factor authentication (2FA)</strong> on every important account</li><li>Never share passwords — no legitimate service will ask for your password</li></ul><h3 id="two-factor-authentication-2fa" tabindex="-1">Two-Factor Authentication (2FA) <a class="header-anchor" href="#two-factor-authentication-2fa" aria-label="Permalink to &quot;Two-Factor Authentication (2FA)&quot;">​</a></h3><p>A second verification step beyond just your password:</p><table tabindex="0"><thead><tr><th>2FA Method</th><th>Description</th></tr></thead><tbody><tr><td><strong>SMS OTP</strong></td><td>One-time password sent to your phone</td></tr><tr><td><strong>Authenticator app</strong></td><td>Time-based code (Google Authenticator, Microsoft Authenticator)</td></tr><tr><td><strong>Hardware key</strong></td><td>Physical key plugged into USB (YubiKey)</td></tr><tr><td><strong>Biometric</strong></td><td>Fingerprint or face recognition as second factor</td></tr></tbody></table><h3 id="safe-browsing" tabindex="-1">Safe Browsing <a class="header-anchor" href="#safe-browsing" aria-label="Permalink to &quot;Safe Browsing&quot;">​</a></h3><ul><li>Check for <strong>HTTPS</strong> and padlock before entering any personal data</li><li>Be suspicious of sites with many pop-ups or redirect you unexpectedly</li><li>Don&#39;t click on links from unknown emails or SMS</li><li>Use <strong>private/incognito mode</strong> for sensitive browsing on shared computers</li><li>Clear browser cache and cookies on shared/public computers</li></ul><h3 id="public-wi-fi" tabindex="-1">Public Wi-Fi <a class="header-anchor" href="#public-wi-fi" aria-label="Permalink to &quot;Public Wi-Fi&quot;">​</a></h3><ul><li><strong>Avoid accessing sensitive accounts</strong> (banking, email) on public Wi-Fi</li><li>Use a <strong>VPN</strong> to encrypt traffic on public networks</li><li>Disable auto-connect to open networks</li><li>Verify the network name with the venue (fake hotspots)</li></ul><hr><h2 id="digital-footprint" tabindex="-1">Digital Footprint <a class="header-anchor" href="#digital-footprint" aria-label="Permalink to &quot;Digital Footprint&quot;">​</a></h2><p>Your <strong>digital footprint</strong> is the trail of data left by everything you do online.</p><h3 id="passive-digital-footprint" tabindex="-1">Passive digital footprint <a class="header-anchor" href="#passive-digital-footprint" aria-label="Permalink to &quot;Passive digital footprint&quot;">​</a></h3><p>Data collected without your active input:</p><ul><li>IP address and location</li><li>Websites visited (cookies, server logs)</li><li>Device type, browser, operating system</li><li>Search queries</li><li>Purchase history</li></ul><h3 id="active-digital-footprint" tabindex="-1">Active digital footprint <a class="header-anchor" href="#active-digital-footprint" aria-label="Permalink to &quot;Active digital footprint&quot;">​</a></h3><p>Data you deliberately create:</p><ul><li>Social media posts</li><li>Comments and reviews</li><li>Forms filled in</li><li>Photos uploaded</li><li>Emails sent</li></ul><h3 id="why-it-matters" tabindex="-1">Why it matters: <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why it matters:&quot;">​</a></h3><ul><li>Employers search candidates&#39; online presence before hiring</li><li>University admission offices check social media</li><li>Insurance companies may use data for risk assessment</li><li>Marketers build profiles for targeted advertising</li><li>Law enforcement can access digital records</li></ul><h3 id="managing-your-digital-footprint" tabindex="-1">Managing your digital footprint: <a class="header-anchor" href="#managing-your-digital-footprint" aria-label="Permalink to &quot;Managing your digital footprint:&quot;">​</a></h3><ul><li>Set social media profiles to <strong>private</strong></li><li>Think before posting — public posts can last forever</li><li>Search your own name to see what&#39;s visible</li><li>Delete old accounts you no longer use</li><li>Use privacy settings on every platform</li><li>Be careful what permissions you grant apps</li></ul><hr><h2 id="cyberbullying" tabindex="-1">Cyberbullying <a class="header-anchor" href="#cyberbullying" aria-label="Permalink to &quot;Cyberbullying&quot;">​</a></h2><p><strong>Cyberbullying</strong> is the use of technology to repeatedly harass, threaten, or humiliate someone.</p><table tabindex="0"><thead><tr><th>Form</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Harassment</strong></td><td>Sending threatening or abusive messages</td></tr><tr><td><strong>Exclusion</strong></td><td>Deliberately leaving someone out of online groups</td></tr><tr><td><strong>Impersonation</strong></td><td>Creating fake accounts pretending to be the victim</td></tr><tr><td><strong>Outing</strong></td><td>Sharing private information or images without consent</td></tr><tr><td><strong>Trolling</strong></td><td>Posting inflammatory content to provoke a reaction</td></tr><tr><td><strong>Cyberstalking</strong></td><td>Following and monitoring someone&#39;s online activity</td></tr></tbody></table><h3 id="effects-on-victims" tabindex="-1">Effects on victims: <a class="header-anchor" href="#effects-on-victims" aria-label="Permalink to &quot;Effects on victims:&quot;">​</a></h3><ul><li>Anxiety, depression, and low self-esteem</li><li>Social withdrawal</li><li>Academic performance drops</li><li>In severe cases: self-harm or suicide</li></ul><h3 id="what-to-do" tabindex="-1">What to do: <a class="header-anchor" href="#what-to-do" aria-label="Permalink to &quot;What to do:&quot;">​</a></h3><ul><li><strong>Don&#39;t respond</strong> — responding often escalates</li><li><strong>Block</strong> the person on all platforms</li><li><strong>Screenshot</strong> evidence before blocking</li><li><strong>Report</strong> to platform (every major platform has reporting tools)</li><li><strong>Tell a trusted adult</strong> — parent, teacher, or counsellor</li><li><strong>Report to SAPS</strong> if threats are made</li></ul><hr><h2 id="online-scams" tabindex="-1">Online Scams <a class="header-anchor" href="#online-scams" aria-label="Permalink to &quot;Online Scams&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scam Type</th><th>How it works</th></tr></thead><tbody><tr><td><strong>Advance fee fraud</strong></td><td>&quot;You won a prize — pay a small fee to claim it&quot;</td></tr><tr><td><strong>Romance scam</strong></td><td>Build online relationship, then request money</td></tr><tr><td><strong>Job scam</strong></td><td>Fake job offer requiring upfront payment</td></tr><tr><td><strong>Fake e-commerce</strong></td><td>Site that takes payment but never delivers</td></tr><tr><td><strong>Lottery scam</strong></td><td>Notification that you&#39;ve won a lottery you never entered</td></tr><tr><td><strong>Tech support scam</strong></td><td>Caller claims to be from Microsoft; your computer has a virus</td></tr></tbody></table><h3 id="rule-of-thumb" tabindex="-1">Rule of thumb: <a class="header-anchor" href="#rule-of-thumb" aria-label="Permalink to &quot;Rule of thumb:&quot;">​</a></h3><blockquote><p><strong>If it sounds too good to be true, it is.</strong></p></blockquote><hr><h2 id="safe-use-of-social-media" tabindex="-1">Safe Use of Social Media <a class="header-anchor" href="#safe-use-of-social-media" aria-label="Permalink to &quot;Safe Use of Social Media&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Do</th><th>Don&#39;t</th></tr></thead><tbody><tr><td>Set profiles to private</td><td>Share your address or daily routine</td></tr><tr><td>Think before posting</td><td>Post while angry or emotional</td></tr><tr><td>Verify information before sharing</td><td>Share unverified news or rumours</td></tr><tr><td>Use strong, unique passwords</td><td>Use your name or birthday as password</td></tr><tr><td>Review app permissions</td><td>Grant all permissions without checking</td></tr><tr><td>Be selective about friend requests</td><td>Accept requests from people you don&#39;t know</td></tr></tbody></table><hr><h2 id="screen-time-and-digital-wellbeing" tabindex="-1">Screen Time and Digital Wellbeing <a class="header-anchor" href="#screen-time-and-digital-wellbeing" aria-label="Permalink to &quot;Screen Time and Digital Wellbeing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Consideration</th></tr></thead><tbody><tr><td><strong>Addiction</strong></td><td>Social media designed to maximise engagement → difficult to stop</td></tr><tr><td><strong>Blue light</strong></td><td>Screens before bed interfere with sleep</td></tr><tr><td><strong>Posture</strong></td><td>Prolonged screen use can cause neck and back problems</td></tr><tr><td><strong>Eye strain</strong></td><td>Follow 20-20-20 rule: every 20 min, look 20 feet away for 20 seconds</td></tr><tr><td><strong>Social comparison</strong></td><td>Social media shows highlights, not reality → unrealistic expectations</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Phishing</strong></td><td>Fake emails/sites designed to steal credentials</td></tr><tr><td><strong>Spear phishing</strong></td><td>Targeted phishing aimed at a specific person</td></tr><tr><td><strong>Smishing</strong></td><td>Phishing via SMS messages</td></tr><tr><td><strong>Vishing</strong></td><td>Phishing via phone calls</td></tr><tr><td><strong>Social engineering</strong></td><td>Manipulating people to reveal information or take harmful actions</td></tr><tr><td><strong>Digital footprint</strong></td><td>Trail of data left by online activity</td></tr><tr><td><strong>Cyberbullying</strong></td><td>Using technology to repeatedly harass or humiliate someone</td></tr><tr><td><strong>2FA</strong></td><td>Two-factor authentication — second verification step</td></tr><tr><td><strong>VPN</strong></td><td>Encrypts internet traffic, protecting data on public networks</td></tr><tr><td><strong>Passive footprint</strong></td><td>Data collected without your active input</td></tr><tr><td><strong>Active footprint</strong></td><td>Data you deliberately create online</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Give FOUR signs that an email might be a phishing attempt&quot;</strong> — urgent language; generic greeting; sender email doesn&#39;t match organisation; suspicious links; requests for passwords; grammar errors; unexpected attachments</p></li><li><p><strong>&quot;What is a digital footprint? Give ONE example of a passive and ONE of an active footprint&quot;</strong> — trail of data left by online activity; passive: websites visited tracked by cookies; active: social media post you published</p></li><li><p><strong>&quot;Give FOUR safe internet practices&quot;</strong> — use strong unique passwords; enable 2FA; check for HTTPS before entering data; avoid sensitive accounts on public Wi-Fi; use VPN on public networks</p></li><li><p><strong>&quot;What is cyberbullying? What should a victim do?&quot;</strong> — using technology to repeatedly harass/humiliate someone; victim should: not respond, block the bully, screenshot evidence, report to platform, tell a trusted adult</p></li><li><p><strong>&quot;Why should you use a VPN on public Wi-Fi?&quot;</strong> — Public Wi-Fi is unencrypted — anyone on the network can intercept your data; VPN creates an encrypted tunnel protecting data from eavesdropping</p></li></ol></div>',62)])])}const p=e(a,[["render",n]]);export{u as __pageData,p as default};
